def search_sorted_matrix(matrix, target):
    """
    2D matriste satır ve sütunlar sıralıyken eleman arayan algoritma.

    Args:
        matrix: 2D sıralı matris (satır ve sütunlar sıralı).
        target: Aranacak hedef eleman.

    Returns:
        Hedef elemanın koordinatlarını (satır, sütun) içeren bir tuple.
        Hedef eleman bulunamazsa None döndürür.
    """
    if not matrix or not matrix[0]:
        return None

    row = 0
    col = len(matrix[0]) - 1

    while row < len(matrix) and col >= 0:
        if matrix[row][col] == target:
            return (row, col)
        elif matrix[row][col] < target:
            row += 1
        else:
            col -= 1

    return None

if __name__ == '__main__':
    # Örnek kullanım
    matrix = [
        [1, 4, 7, 11, 15],
        [2, 5, 8, 12, 19],
        [3, 6, 9, 16, 22],
        [10, 13, 14, 17, 24],
        [18, 21, 23, 26, 30]
    ]

    target = 5
    result = search_sorted_matrix(matrix, target)

    if result:
        print(f"Hedef {target} bulundu, Konum: {result}")
    else:
        print(f"Hedef {target} bulunamadı.")

